        "file": "foodOnline/settings.py",
        "code": "\"\"\"\nDjango settings for foodOnline project.\n\nGenerated by 'django-admin startproject' using Django 5.0.1.\n\nFor more information on this file, see\nhttps://docs.djangoproject.com/en/5.0/topics/settings/\n\nFor the full list of settings and their values, see\nhttps://docs.djangoproject.com/en/5.0/ref/settings/\n\"\"\"\n\n#import os\nfrom pathlib import Path\nfrom decouple import config\nfrom django.contrib.messages import constants as messages\n\n# Build paths inside the project like this: BASE_DIR / 'subdir'.\nBASE_DIR = Path(__file__).resolve().parent.parent\n\n\n# Quick-start development settings - unsuitable for production\n# See https://docs.djangoproject.com/en/5.0/howto/deployment/checklist/\n\n# SECURITY WARNING: keep the secret key used in production secret!\nSECRET_KEY = config('SECRET_KEY')\n\n# SECURITY WARNING: don't run with debug turned on in production!\nDEBUG = config('DEBUG', cast=bool)\n\nALLOWED_HOSTS = []\n\n\n# Application definition\n\nINSTALLED_APPS = [\n    'django.contrib.admin',\n    'django.contrib.auth',\n    'django.contrib.contenttypes',\n    'django.contrib.sessions',\n    'django.contrib.messages',\n    'django.contrib.staticfiles',\n\n    'accounts',\n    'vendor',\n    'menu',\n    'marketplace',\n    'django.contrib.gis',\n    'customers',\n    'orders',\n]\n\nMIDDLEWARE = [\n    'django.middleware.security.SecurityMiddleware',\n    'django.contrib.sessions.middleware.SessionMiddleware',\n    'django.middleware.common.CommonMiddleware',\n    'django.middleware.csrf.CsrfViewMiddleware',\n    'django.contrib.auth.middleware.AuthenticationMiddleware',\n    'django.contrib.messages.middleware.MessageMiddleware',\n    'django.middleware.clickjacking.XFrameOptionsMiddleware', \n    'orders.request_object.RequestObjectMiddleware', # Custom Middleware created to access the request object in models.py  \n]\n\nROOT_URLCONF = 'foodOnline.urls'\n\nTEMPLATES = [\n    {\n        'BACKEND': 'django.template.backends.django.DjangoTemplates',\n        'DIRS': ['templates'],\n        'APP_DIRS': True,\n        'OPTIONS': {\n            'context_processors': [\n                'django.template.context_processors.debug',\n                'django.template.context_processors.request',\n                'django.contrib.auth.context_processors.auth',\n                'django.contrib.messages.context_processors.messages',\n                'accounts.context_processors.get_vendor',\n                'accounts.context_processors.get_google_api',\n                'marketplace.context_processors.get_cart_counter',\n                'marketplace.context_processors.get_cart_amounts',\n                'accounts.context_processors.get_user_profile',\n                'accounts.context_processors.get_paypal_api',\n            ],\n        },\n    },\n]\n\nWSGI_APPLICATION = 'foodOnline.wsgi.application'\n\n\n# Database\n# https://docs.djangoproject.com/en/5.0/ref/settings/#databases\n\nDATABASES = {\n    'default': {\n        #'ENGINE': 'django.db.backends.postgresql',\n        'ENGINE': 'django.contrib.gis.db.backends.postgis',\n        'NAME': config('DB_NAME'),\n        'USER': config('DB_USER'),\n        'PASSWORD': config('DB_PASSWORD'),\n        'HOST': config('DB_HOST'),\n    }\n}\n\nAUTH_USER_MODEL = 'accounts.User'\n\n\n# Password validation\n# https://docs.djangoproject.com/en/5.0/ref/settings/#auth-password-validators\n\nAUTH_PASSWORD_VALIDATORS = [\n    {\n        'NAME': 'django.contrib.auth.password_validation.UserAttributeSimilarityValidator',\n    },\n    {\n        'NAME': 'django.contrib.auth.password_validation.MinimumLengthValidator',\n    },\n    {\n        'NAME': 'django.contrib.auth.password_validation.CommonPasswordValidator',\n    },\n    {\n        'NAME': 'django.contrib.auth.password_validation.NumericPasswordValidator',\n    },\n]\n\n\n# Internationalization\n# https://docs.djangoproject.com/en/5.0/topics/i18n/\n\nLANGUAGE_CODE = 'en-us'\n\nTIME_ZONE = 'UTC'\n\nUSE_I18N = True\n\nUSE_TZ = True\n\n\n# Static files (CSS, JavaScript, Images)\n# https://docs.djangoproject.com/en/5.0/howto/static-files/\n\nSTATIC_URL = 'static/'\nSTATIC_ROOT = BASE_DIR /'static'\nSTATICFILES_DIRS = [\n    'foodOnline/static'\n]\n\nMEDIA_URL = '/media/'\nMEDIA_ROOT = BASE_DIR /'media'\n\n# Default primary key field type\n# https://docs.djangoproject.com/en/5.0/ref/settings/#default-auto-field\n\nDEFAULT_AUTO_FIELD = 'django.db.models.BigAutoField'\n\nMESSAGE_TAGS = {\n    messages.ERROR: \"danger\",\n}\n\n# Email Configuration\nEMAIL_HOST = config('EMAIL_HOST')\nEMAIL_PORT = config('EMAIL_PORT', cast=int)\nEMAIL_HOST_USER = config('EMAIL_HOST_USER')\nEMAIL_HOST_PASSWORD = config('EMAIL_HOST_PASSWORD')\nEMAIL_USE_TLS = True\nDEFAULT_FROM_EMAIL = config('DEFAULT_FROM_EMAIL')\n\nGOOGLE_API_KEY = config('GOOGLE_API_KEY')\n\n# Showing the path of the library GDAL \n\n#if DEBUG == True:\n#    os.environ['PATH'] = os.path.join(BASE_DIR, 'env\\Lib\\site-packages\\osgeo') + ';' + os.environ['PATH']\n#    os.environ['PROJ_LIB'] = os.path.join(BASE_DIR, 'env\\Lib\\site-packages\\osgeo\\data\\proj') + ';' + os.environ['PATH']\n#    GDAL_LIBRARY_PATH = os.path.join(BASE_DIR, 'env\\Lib\\site-packages\\osgeo\\gdal304.dll')\n\nPAYPAL_CLIENT_ID = config('PAYPAL_CLIENT_ID')\n\nSECURE_CROSS_ORIGIN_OPENER_POLICY = 'same-origin-allow-popups'\n\nRZP_KEY_ID = config('RZP_KEY_ID')\nRZP_KEY_SECRET = config('RZP_KEY_SECRET')\n",
