        "code": "const mysql = require('mysql2');\n\nconst connection = mysql.createConnection({\n\n    host: 'localhost',\n    user: 'user',\n    database: 'saboroso',\n    password: 'Zilda19121956*',\n    multipleStatements: true\n\n});\n\nmodule.exports = connection;",
