        "code": "/*\n\n * TamperLogProtector.cpp - watches access logs and records tamper alerts\n\n */\n\n\n\n#include <QCoreApplication>\n\n#include <QCryptographicHash>\n\n#include <QDir>\n\n#include <QFile>\n\n#include <QFileInfo>\n\n#include <QTimer>\n#include <QThread>\n\n\n\n#include \"VeyonCore.h\"\n\n#include \"AccessLogWriter.h\"\n\n#include \"BuiltinFeatures.h\"\n\n#include \"FeatureWorkerManager.h\"\n\n#include \"Logger.h\"\n#include \"SystemTrayIcon.h\"\n#include \"TamperLogProtector.h\"\n\n\n\nnamespace\n\n{\n\n\n\nconstexpr auto AdminPasswordHash = \"8ab2cdcbd95fabaab0ef54a74c84a08b3e8c95c511f50c4992e9a8cac3c63863\";\n\n\n\nQString passwordSha256Hex( const QString& password )\n\n{\n\n\treturn QString::fromLatin1(\n\n\t\tQCryptographicHash::hash( password.toUtf8(), QCryptographicHash::Sha256 ).toHex() );\n\n}\n\n\n\n}\n\n\n\nvoid TamperLogProtector::writeTamperResponse( const QString& response )\n\n{\n\n\tconst auto responsePath = QDir( QCoreApplication::applicationDirPath() ).filePath(\n\n\t\tQStringLiteral( \"acessos_tamper_response.txt\" ) );\n\n\n\n\tQFile file( responsePath );\n\n\tif( file.open( QIODevice::WriteOnly | QIODevice::Text | QIODevice::Truncate ) )\n\n\t{\n\n\t\tfile.write( response.toUtf8() );\n\n\t}\n\n}\n\n\n\nTamperLogProtector::TamperLogProtector( FeatureWorkerManager& featureWorkerManager, QObject* parent ) :\n\n\tQObject( parent ),\n\n\tm_featureWorkerManager( featureWorkerManager )\n\n{\n\n\trefreshBackups();\n\n\tauto* pollTimer = new QTimer( this );\n\n\tconnect( pollTimer, &QTimer::timeout, this, [this]() {\n\n\t\tcheckNetworkAccessFile();\n\n\t\tcheckNetworkFile();\n\n\t} );\n\n\tpollTimer->start( 1000 );\n\n\tVeyonCore::builtinFeatures().systemTrayIcon().ensureSessionWorker( m_featureWorkerManager );\n\n}\n\n\n\nbool TamperLogProtector::isAccessLogPath( const QString& filePath ) const\n\n{\n\n\treturn filePath == AccessLogWriter::networkAccessLogPath();\n\n}\n\n\n\nvoid TamperLogProtector::setWatcherSuppressed( bool suppressed )\n\n{\n\n\tif( suppressed )\n\n\t{\n\n\t\t++m_suppressWatcherDepth;\n\n\t}\n\n\telse if( m_suppressWatcherDepth > 0 )\n\n\t{\n\n\t\t--m_suppressWatcherDepth;\n\n\t}\n\n}\n\n\n\nvoid TamperLogProtector::beginProtectedBatch()\n\n{\n\n\tsetWatcherSuppressed( true );\n\n}\n\n\n\nvoid TamperLogProtector::endProtectedBatch()\n\n{\n\n\trefreshBackups();\n\n\tsetWatcherSuppressed( false );\n\n}\n\n\n\nvoid TamperLogProtector::refreshBackups()\n\n{\n\n\tQString content;\n\n\n\n\tif( AccessLogWriter::tryReadLogFileContent( AccessLogWriter::networkAccessLogPath(), content ) )\n\n\t{\n\n\t\tm_networkAccessBackup = content;\n\n\t}\n\n\tif( AccessLogWriter::tryReadLogFileContent( AccessLogWriter::networkTamperedLogPath(), content ) )\n\n\t{\n\n\t\tm_networkBackup = content;\n\n\t}\n\n}\n\n\n\nvoid TamperLogProtector::prepareWrite( const QString& filePath )\n\n{\n\n\tQ_UNUSED( filePath )\n\n\tsetWatcherSuppressed( true );\n\n}\n\n\n\nvoid TamperLogProtector::finalizeWrite( const QString& filePath )\n\n{\n\n\tupdateBackupForPath( filePath );\n\n\tsetWatcherSuppressed( false );\n\n}\n\n\n\nvoid TamperLogProtector::updateBackupForPath( const QString& filePath )\n\n{\n\n\tQString content;\n\n\n\n\tif( filePath == AccessLogWriter::networkAccessLogPath() )\n\n\t{\n\n\t\tif( AccessLogWriter::tryReadLogFileContent( filePath, content ) )\n\n\t\t{\n\n\t\t\tm_networkAccessBackup = content;\n\n\t\t}\n\n\t}\n\n\telse if( filePath == AccessLogWriter::networkTamperedLogPath() )\n\n\t{\n\n\t\tif( AccessLogWriter::tryReadLogFileContent( filePath, content ) )\n\n\t\t{\n\n\t\t\tm_networkBackup = content;\n\n\t\t}\n\n\t}\n\n}\n\n\n\nbool TamperLogProtector::verifyAdminPassword( const QString& password )\n\n{\n\n\treturn passwordSha256Hex( password ) == QLatin1String( AdminPasswordHash );\n\n}\n\n\n\nvoid TamperLogProtector::reportUnauthorizedChange( const QString& filePath, const QString& fileLabel )\n\n{\n\n\tvWarning() << \"[tamper-log-protection] unauthorized change detected on\" << fileLabel;\n\n\n\n\tif( isAccessLogPath( filePath ) && QFile::exists( filePath ) )\n\n\t{\n\n\t\tAccessLogWriter::recordTamperAlertForAccessLogTamper( filePath, QStringLiteral( \"rede\" ) );\n\n\t}\n\n\n\n\tupdateBackupForPath( filePath );\n\n}\n\n\n\nvoid TamperLogProtector::checkProtectedFile( const QString& filePath, const QString& backup, const QString& fileLabel )\n\n{\n\n\tif( isWatcherSuppressed() )\n\n\t{\n\n\t\treturn;\n\n\t}\n\n\n\n\tif( QFile::exists( filePath ) == false )\n\n\t{\n\n\t\tif( backup.isEmpty() == false )\n\n\t\t{\n\n\t\t\treportUnauthorizedChange( filePath, fileLabel );\n\n\t\t}\n\n\t\treturn;\n\n\t}\n\n\n\n\tQString currentContent;\n\n\tif( AccessLogWriter::tryReadLogFileContent( filePath, currentContent ) == false )\n\n\t{\n\n\t\tvWarning() << \"[tamper-log-protection] skipping check due to read failure on\" << fileLabel;\n\n\t\treturn;\n\n\t}\n\n\n\n\tif( AccessLogWriter::logContentsEqual( currentContent, backup ) )\n\n\t{\n\n\t\treturn;\n\n\t}\n\n\n\n\tif( AccessLogWriter::isLegitimateProtectedLogAppend( backup, currentContent ) )\n\n\t{\n\n\t\tupdateBackupForPath( filePath );\n\n\t\treturn;\n\n\t}\n\n\n\n\tQString retryContent;\n\n\tQThread::msleep( 400 );\n\n\tif( AccessLogWriter::tryReadLogFileContent( filePath, retryContent ) &&\n\n\t\tAccessLogWriter::isLegitimateProtectedLogAppend( backup, retryContent ) )\n\n\t{\n\n\t\tupdateBackupForPath( filePath );\n\n\t\treturn;\n\n\t}\n\n\n\n\tif( isAccessLogPath( filePath ) && AccessLogWriter::accessLogFileHasValidIntegrity( filePath ) )\n\n\t{\n\n\t\tvDebug() << \"[tamper-log-protection] ignoring change on access log with valid hashes\";\n\n\t\tupdateBackupForPath( filePath );\n\n\t\treturn;\n\n\t}\n\n\n\n\treportUnauthorizedChange( filePath, fileLabel );\n\n}\n\n\n\nvoid TamperLogProtector::checkNetworkAccessFile()\n\n{\n\n\tcheckProtectedFile( AccessLogWriter::networkAccessLogPath(), m_networkAccessBackup,\n\n\t\t\t\t\t\tQStringLiteral( \"rede acessos_veyon\" ) );\n\n}\n\n\n\nvoid TamperLogProtector::checkNetworkFile()\n\n{\n\n\tcheckProtectedFile( AccessLogWriter::networkTamperedLogPath(), m_networkBackup,\n\n\t\t\t\t\t\tQStringLiteral( \"rede acessos_veyon_ad\" ) );\n\n}\n\n\n\n",
